ALGORITHM MPI_Timing_Pattern
INPUT: None
OUTPUT: Parallel execution time in seconds

BEGIN
 // Initialize MPI environment
 CALL MPI_Init(argc, argv)
 CALL MPI_Comm_rank(MPI_COMM_WORLD, rank)

 // Step 1: Synchronize all processes before starting timer
 CALL MPI_Barrier(MPI_COMM_WORLD)

 // Step 2: Only rank 0 records start time
 IF rank == 0 THEN
 start_time = MPI_Wtime()
 END IF

 // Step 3: Perform parallel computation
 // ... parallel work happens here ...
 // Each process does its portion of work
 // Communication may occur between processes

 // Step 4: Synchronize all processes before stopping timer
 CALL MPI_Barrier(MPI_COMM_WORLD)

 // Step 5: Only rank 0 records end time and computes elapsed time
 IF rank == 0 THEN
 end_time = MPI_Wtime()
 elapsed_time = end_time - start_time
 PRINT "Parallel execution time: " + elapsed_time + " seconds"
 END IF

 // Cleanup
 CALL MPI_Finalize()
END

/*
 * MPI Timing Example - C Implementation
 * Demonstrates accurate timing measurement for MIMD parallel programs
 * Topic: Taking Timings of MIMD Programs
 */

#include <mpi.h>
#include <stdio.h>
#include <math.h>
#include <stdlib.h>

/* Function to simulate parallel computation with varying workload */
double parallel_work(int rank) {
 // Simulate different amounts of work per process (load imbalance)
 int iterations = 10000 + (rank * 1000);
 double result = 0.0;

 for (int i = 1; i < iterations; i++) {
 result += sqrt((double)i) * sin((double)i);
 }
 return result;
}

int main(int argc, char** argv) {
 int rank, size;
 double start_time, end_time, parallel_time;
 double local_result, total_result;

 // Initialize MPI
 MPI_Init(&argc, &argv);
 MPI_Comm_rank(MPI_COMM_WORLD, &rank);
 MPI_Comm_size(MPI_COMM_WORLD, &size);

 /* ============================================
 * TIMING PATTERN FOR MPI PROGRAMS
 * ============================================ */

 // Step 1: Barrier synchronization - ensure all processes reach this point
 MPI_Barrier(MPI_COMM_WORLD);

 // Step 2: Only rank 0 records the start time
 if (rank == 0) {
 start_time = MPI_Wtime();
 }

 // Step 3: PARALLEL WORK SECTION
 // Each process performs its portion of the computation
 local_result = parallel_work(rank);

 // Optional: Reduce results to simulate communication
 MPI_Reduce(&local_result, &total_result, 1, MPI_DOUBLE, 
 MPI_SUM, 0, MPI_COMM_WORLD);
 // ============================================

 // Step 4: Barrier synchronization - ensure all work is complete
 MPI_Barrier(MPI_COMM_WORLD);

 // Step 5: Only rank 0 records end time and computes elapsed time
 if (rank == 0) {
 end_time = MPI_Wtime();
 parallel_time = end_time - start_time;

 printf("======================================\n");
 printf(" MPI TIMING RESULTS \n");
 printf("======================================\n");
 printf("Number of processes: %d\n", size);
 printf("Parallel execution time: %.6f seconds\n", parallel_time);
 printf("Total computation: %.2f\n", total_result);

 /* Calculate performance metrics */
 double estimated_seq_time = parallel_time * size; // Theoretical
 double speedup = estimated_seq_time / parallel_time;
 double efficiency = (speedup / size) * 100.0;

 printf("\n--- Performance Metrics ---\n");
 printf("Estimated Speedup: %.2fx\n", speedup);
 printf("Parallel Efficiency: %.1f%%\n", efficiency);
 printf("======================================\n");
 }

 // Finalize MPI
 MPI_Finalize();
 return 0;
}

/* 
 * COMPILE: mpicc -o mpi_timing mpi_timing.c -lm
 * RUN: mpirun -n 4 ./mpi_timing
 * 
 * Key Points:
 * 1. MPI_Wtime() returns wall-clock time in seconds (high resolution)
 * 2. MPI_Barrier() ensures all processes synchronize before/after timing
 * 3. Only rank 0 needs to record times (others just sync)
 * 4. Multiple runs should be averaged for accuracy
 */
